"use strict";(globalThis.webpackChunkmydocs=globalThis.webpackChunkmydocs||[]).push([[849],{6164:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docs":[{"type":"link","href":"/docs/","label":"SENEX Intelligent Chain","docId":"index","unlisted":false},{"type":"category","label":"Architecture","collapsed":false,"items":[{"type":"link","href":"/docs/architecture/genome","label":"GENOME (Global Self-Evolving AI Mind)","docId":"architecture/genome","unlisted":false},{"type":"link","href":"/docs/architecture/aia_agents","label":"AIA AGENTS (Adaptive Intelligence Assistants)","docId":"architecture/aia_agents","unlisted":false},{"type":"link","href":"/docs/architecture/intelligent_chain","label":"INTELLIGENT CHAIN (Blockchain Infrastructure)","docId":"architecture/intelligent_chain","unlisted":false}],"collapsible":true,"href":"/docs/architecture/"},{"type":"category","label":"AIA Chain","collapsed":false,"items":[{"type":"category","label":"Architecture","items":[{"type":"link","href":"/docs/aia/architecture/secure-remote","label":"Secure Remote Architecture","docId":"aia/architecture/secure-remote","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Smart Contracts","items":[{"type":"link","href":"/docs/aia/contracts/overview","label":"Smart Contract Overview","docId":"aia/contracts/overview","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Guides","items":[{"type":"link","href":"/docs/aia/guides/contributor-guide","label":"Contributor Guide","docId":"aia/guides/contributor-guide","unlisted":false}],"collapsed":true,"collapsible":true}],"collapsible":true,"href":"/docs/aia/"},{"type":"category","label":"Privacy","items":[{"type":"link","href":"/docs/privacy/technologies","label":"Privacy Technologies (Target Design)","docId":"privacy/technologies","unlisted":false},{"type":"link","href":"/docs/privacy/mathematical_guarantees","label":"Mathematical Privacy Guarantee (Target Design)","docId":"privacy/mathematical_guarantees","unlisted":false},{"type":"link","href":"/docs/privacy/threat_model","label":"Security Threat Model & Mitigations","docId":"privacy/threat_model","unlisted":false},{"type":"link","href":"/docs/privacy/compliance","label":"Privacy Compliance & Guarantees","docId":"privacy/compliance","unlisted":false}],"collapsed":true,"collapsible":true,"href":"/docs/privacy/"},{"type":"category","label":"Tokenomics","items":[{"type":"link","href":"/docs/tokenomics/distribution","label":"Initial Distribution","docId":"tokenomics/distribution","unlisted":false},{"type":"link","href":"/docs/tokenomics/incentives","label":"Incentives & Rewards","docId":"tokenomics/incentives","unlisted":false},{"type":"link","href":"/docs/tokenomics/security","label":"Economic Security Model","docId":"tokenomics/security","unlisted":false},{"type":"link","href":"/docs/tokenomics/staking","label":"Staking Mechanisms","docId":"tokenomics/staking","unlisted":false}],"collapsed":true,"collapsible":true,"href":"/docs/tokenomics/"},{"type":"link","href":"/docs/governance","label":"Governance Model","docId":"governance","unlisted":false},{"type":"link","href":"/docs/applications","label":"Applications & Use Cases","docId":"applications","unlisted":false},{"type":"link","href":"/docs/scalability","label":"Scalability & Performance","docId":"scalability","unlisted":false},{"type":"link","href":"/docs/migration","label":"Token Migration & Upgrade Path","docId":"migration","unlisted":false},{"type":"link","href":"/docs/innovation","label":"Technical Innovation Summary","docId":"innovation","unlisted":false},{"type":"link","href":"/docs/roadmap","label":"Roadmap & Deployment Strategy","docId":"roadmap","unlisted":false}]},"docs":{"aia/architecture/secure-remote":{"id":"aia/architecture/secure-remote","title":"Secure Remote Architecture","description":"Overview","sidebar":"docs"},"aia/contracts/overview":{"id":"aia/contracts/overview","title":"Smart Contract Overview","description":"AIA_Chain.sol","sidebar":"docs"},"aia/guides/contributor-guide":{"id":"aia/guides/contributor-guide","title":"Contributor Guide","description":"Welcome to the AIA Chain! This guide will help you get started as a contributor - someone who submits AI inference requests to the network.","sidebar":"docs"},"aia/index":{"id":"aia/index","title":"AIA Chain Documentation","description":"Welcome to the technical documentation for AIA Chain - a decentralized AI inference network built on the SENEX Intelligent Chain.","sidebar":"docs"},"applications":{"id":"applications","title":"Applications & Use Cases","description":"These examples illustrate where the SENEX design is headed. They combine shipped capabilities (local-first processing, governed sharing) with roadmap ones (MPC aggregation, network-scale GENOME). Compliance references are design goals, not certifications.","sidebar":"docs"},"architecture/aia_agents":{"id":"architecture/aia_agents","title":"AIA AGENTS (Adaptive Intelligence Assistants)","description":"Client-side secure agents running on user devices with full local data access and privacy-first design.","sidebar":"docs"},"architecture/genome":{"id":"architecture/genome","title":"GENOME (Global Self-Evolving AI Mind)","description":"GENOME is the network mind that is designed to emerge from connected agents\' data, computation, proofs, and outcomes. The federated training, on-chain coordination, and validator-scale execution described here are target design, not a running system today.","sidebar":"docs"},"architecture/index":{"id":"architecture/index","title":"System Architecture Overview","description":"These three pillars describe the full SENEX design. Live in v1.0-alpha: local-first AIA agents, the permissioned testnet, and the intelligence-economy loop (Proof of Data + Proof of Computation \u2192 Proof of Intel). GENOME as a network-scale mind and the custom chain are roadmap \u2014 see each page for status.","sidebar":"docs"},"architecture/intelligent_chain":{"id":"architecture/intelligent_chain","title":"INTELLIGENT CHAIN (Blockchain Infrastructure)","description":"Today (v1.0-alpha): a contribution ledger where every node recomputes and verifies each iteration and seals a hash-chained record before settlement (block-style verification). The custom Layer 1, Polygon phase, ERC-20 token, and Proof-of-Contribution consensus described below are roadmap design, not deployed. ASHA accounting is simulation-only.","sidebar":"docs"},"genome/index":{"id":"genome/index","title":"GENOME Technical Documentation","description":"This section is dedicated to the technical implementation details of GENOME (Global Self-Evolving AI Mind)."},"governance":{"id":"governance","title":"Governance Model","description":"This describes the intended governance design. Token-holder governance references the simulated ASHA unit (not live or tradeable); these mechanisms are not yet active on a live network.","sidebar":"docs"},"index":{"id":"index","title":"SENEX Intelligent Chain","description":"Complete System Documentation","sidebar":"docs"},"innovation":{"id":"innovation","title":"Technical Innovation Summary","description":"SENEX is built on a set of named inventions. Several are live in v1.0-alpha; others are named research directions on the roadmap. We describe what each one does \u2014 the underlying constructions are proprietary.","sidebar":"docs"},"migration":{"id":"migration","title":"Token Migration & Upgrade Path","description":"This is the planned token-platform path. There is no live ASHA token on Polygon or any chain today; ASHA is a simulated accounting unit with transferability disabled. The phases below are design intent, not a deployed state, and nothing here is an offer or financial advice.","sidebar":"docs"},"privacy/compliance":{"id":"privacy/compliance","title":"Privacy Compliance & Guarantees","description":"The frameworks below are compliance goals the architecture is designed toward, not audited certifications. Local-first data handling makes them achievable, but no formal GDPR/CCPA/HIPAA/COPPA certification has been completed.","sidebar":"docs"},"privacy/index":{"id":"privacy/index","title":"Privacy & Security Architecture","description":"SENEX is built local-first: your data and the raw locations of your data stay on your device, and nothing is shared without an explicit, governed, revocable grant. On top of that foundation, SENEX is designing a cryptographic privacy stack so that even the contributions a node makes to the network reveal as little as possible.","sidebar":"docs"},"privacy/mathematical_guarantees":{"id":"privacy/mathematical_guarantees","title":"Mathematical Privacy Guarantee (Target Design)","description":"Differential privacy is not yet implemented in the shipping product. This page describes the target privacy model SENEX is designing toward. Today, privacy is enforced by local-first governance: raw data and locators never leave the device, sharing is bounded and revocable. Do not read the parameters below as an active mathematical guarantee.","sidebar":"docs"},"privacy/technologies":{"id":"privacy/technologies","title":"Privacy Technologies (Target Design)","description":"The cryptographic mechanisms on this page describe the privacy architecture SENEX is building toward, not features shipping in v1.0-alpha. Today, privacy is enforced by local-first governance (raw data and locators never leave the device; bounded, revocable neurolink sharing). Treat the parameters below as design targets.","sidebar":"docs"},"privacy/threat_model":{"id":"privacy/threat_model","title":"Security Threat Model & Mitigations","description":"This is the threat model for the complete SENEX architecture. Mitigations that depend on the cryptographic stack (differential privacy, secure multi-party computation, zero-knowledge proofs) describe the target design, not v1.0-alpha behavior. What is enforced today: permissioned admission, signed and replay-protected messaging, governed/revocable neurolink sharing, full-node re-execution (block-style verification) with slashing of nodes that submit false results, and a bearer-token-protected local API.","sidebar":"docs"},"roadmap":{"id":"roadmap","title":"Roadmap & Deployment Strategy","description":"Phase 1: Local-first permissioned alpha \u2014 shipping now (v1.0-alpha)","sidebar":"docs"},"scalability":{"id":"scalability","title":"Scalability & Performance","description":"The numbers below are design targets for the full network, not measured production figures. Today\'s alpha runs a local-first agent and a permissioned multi-node testnet.","sidebar":"docs"},"tokenomics/distribution":{"id":"tokenomics/distribution","title":"Initial Distribution","description":"These allocations describe a proposed design. ASHA is a simulated accounting unit, not a live or tradeable token; no ICO or sale is live or open, and nothing here is an offer or solicitation. Figures are illustrative and subject to change.","sidebar":"docs"},"tokenomics/incentives":{"id":"tokenomics/incentives","title":"Incentives & Rewards","description":"The fees and reward splits below model the intelligence economy. ASHA is a simulated accounting unit (transferability disabled in the runtime), so these are design parameters, not live prices or payouts.","sidebar":"docs"},"tokenomics/index":{"id":"tokenomics/index","title":"Tokenomics & Incentive Model","description":"ASHA is a simulated accounting unit used to model the intelligence economy. It is not a live, transferable, or tradeable token. There is no live ICO or token sale. Nothing in these tokenomics pages is an offer to sell or buy, a solicitation, investment or financial advice, or a security. Every figure here describes a design model, subject to change. In the shipping runtime, ASHA accounting is simulation-only with transferability disabled.","sidebar":"docs"},"tokenomics/security":{"id":"tokenomics/security","title":"Economic Security Model","description":"This analysis models the security of the proposed economy. ASHA is a simulated accounting unit (not live or tradeable); the costs and prices below are illustrative design figures.","sidebar":"docs"},"tokenomics/staking":{"id":"tokenomics/staking","title":"Staking Mechanisms","description":"Staking, APY, burning, buy-back, and revenue-sharing described here are design parameters of a simulated economy, not live financial products or yields. ASHA is not a live or tradeable token and these mechanisms are not active. Nothing here is investment advice, a yield offer, or a security. No expectation of profit should be inferred.","sidebar":"docs"}}}}')}}]);